def build_otpauth_uri(
    secret: str,
    account_name: str,
    issuer: str,
    digits: int = 6,
    period: int = 30,
    algorithm: str = "SHA1",
) -> str:
    label = urllib.parse.quote(f"{issuer}:{account_name}")
    params = {
        "secret": secret,
        "issuer": issuer,
        "algorithm": algorithm.upper(),
        "digits": str(digits),
        "period": str(period),
    }
    query = urllib.parse.urlencode(params, quote_via=urllib.parse.quote)
    return f"otpauth://totp/{label}?{query}"


